import okhttp3.Interceptor
import okhttp3.OkHttpClient
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import retrofit2.http.GET
import retrofit2.http.Header

interface UserService {
    @GET("users")
    suspend fun getUsers(@Header("Authorization") token: String): List<User>
}

data class User(val id: Int, val name: String, val email: String)

object NetworkModule {
    private const val BASE_URL_DEV = "https://api.example.com/dev/"
    private const val BASE_URL_STAGING = "https://api.example.com/staging/"
    private const val BASE_URL_PROD = "https://api.example.com/prod/"

    fun createRetrofitInstance(environment: String, authToken: String): Retrofit {
        val httpClient = OkHttpClient.Builder()
            .addInterceptor { chain ->
                val originalRequest = chain.request()
                val requestWithToken = originalRequest.newBuilder()
                    .header("Authorization", authToken)
                    .build()
                chain.proceed(requestWithToken)
            }
            .build()

        return Retrofit.Builder()
            .baseUrl(getBaseUrl(environment))
            .client(httpClient)
            .addConverterFactory(GsonConverterFactory.create())
            .build()
    }

    private fun getBaseUrl(environment: String): String {
        return when (environment) {
            "dev" -> BASE_URL_DEV
            "staging" -> BASE_URL_STAGING
            "prod" -> BASE_URL_PROD
            else -> throw IllegalArgumentException("Invalid environment")
        }
    }
}

// Usage example:
suspend fun fetchUsers(environment: String, authToken: String): List<User> {
    val retrofit = NetworkModule.createRetrofitInstance(environment, authToken)
    val userService = retrofit.create(UserService::class.java)
    return userService.getUsers(authToken)
